using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _service = new NotificationService();
            // Drain the static queue to avoid cross-test contamination
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            // Drain the queue after each test
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesNotificationWithCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("UPDATE", notification.Operation);
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_DeleteOperation_UsesId()
        {
            _service.SendNotification("Student", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UpdateOperation_UsesId()
        {
            _service.SendNotification("Instructor", "10", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Instructor (ID: 10) has been updated", notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsFifoOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Student", "2", EntityOperation.CREATE);
            _service.SendNotification("Student", "3", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.AreEqual("1", first.EntityId);
            Assert.AreEqual("2", second.EntityId);
            Assert.AreEqual("3", third.EntityId);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            Assert.IsNotNull(first);

            var second = _service.ReceiveNotification();
            Assert.IsNull(second);
        }

        [TestMethod]
        public void SendNotification_QueueOverflow_EnforcesMaxLength()
        {
            // Add more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Count remaining in queue
            int count = 0;
            while (_service.ReceiveNotification() != null) count++;
            Assert.IsTrue(count <= 500, $"Queue should enforce max 500, but had {count}");
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory, just ensure it doesn't throw
            _service.MarkAsRead(1);
            _service.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            service.Dispose();
            // Should not throw on double dispose
            service.Dispose();
        }

        [TestMethod]
        public void SendNotification_WhitespaceDisplayName_UsesIdFallback()
        {
            _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_EmptyDisplayName_UsesIdFallback()
        {
            _service.SendNotification("Student", "1", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }
    }
}

