using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = SchoolContextHelper.CreateInMemoryContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_WithNoStudents_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithStudents_ReturnsGroupedData()
        {
            var date1 = new DateTime(2023, 9, 1);
            var date2 = new DateTime(2024, 1, 15);
            _context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = date1 },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = date1 },
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = date2 }
            );
            _context.SaveChanges();

