using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = SchoolContextHelper.CreateInMemoryContext();
            _controller = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedData()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>()
            };
            var course2 = new Course
            {
                CourseID = 2021,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>()
            };
            _context.Courses.AddRange(course1, course2);

            var instructor = new Instructor
            {
                LastName = "Kim",
                FirstMidName = "Abercrombie",
                HireDate = new DateTime(2000, 1, 1),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" },
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 1050 }
                }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
        }

        #region Index Tests

        [TestMethod]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            SeedData();

            var result = _controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Instructors.Any());
        }

        [TestMethod]
        public void Index_WithInstructorId_SetsCoursesInModel()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Index(instructorId, null) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.IsTrue(model.Courses.Any());
            Assert.AreEqual(instructorId, _controller.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Index_WithCourseId_SetsEnrollmentsInModel()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            // Add an enrollment to the course
            _context.Students.Add(new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 1, 1)
            });
            _context.SaveChanges();
            var studentId = _context.Students.First().ID;
            _context.Enrollments.Add(new Enrollment
            {
                CourseID = 1050,
                StudentID = studentId,
                Grade = Grade.A
            });
            _context.SaveChanges();

            var result = _controller.Index(instructorId, 1050) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model.Enrollments);
            Assert.AreEqual(1050, _controller.ViewBag.CourseID);
        }

        [TestMethod]
        public void Index_EmptyDatabase_ReturnsEmptyInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsFalse(model.Instructors.Any());
        }

        #endregion

        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Details_ValidId_ReturnsInstructor()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Details(instructorId) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.AreEqual("Kim", model.LastName);
        }

        #endregion

        #region Create GET Tests

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            SeedData();

            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.CourseAssignments);
            Assert.AreEqual(0, model.CourseAssignments.Count);
            Assert.IsNotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Create POST Tests

        [TestMethod]
        public void Create_Post_ValidInstructor_NoSelectedCourses_RedirectsToIndex()
        {
            SeedData();
            var instructor = new Instructor
            {
                LastName = "New",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
        }

        [TestMethod]
        public void Create_Post_ValidInstructor_WithSelectedCourses_SavesCourseAssignments()
        {
            SeedData();
            var instructor = new Instructor
            {
                LastName = "New",
                FirstMidName = "Instructor",
                HireDate = new DateTime(2023, 1, 1)
            };
            var selectedCourses = new[] { "1050", "2021" };

            _controller.Create(instructor, selectedCourses);

            var saved = _context.Instructors.Where(i => i.LastName == "New").First();
            // The course assignments are added
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.AreEqual(2, assignments.Count);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            SeedData();
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Edit GET Tests

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsInstructor()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Edit((int?)instructorId) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Kim", model.LastName);
            Assert.IsNotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region UpdateInstructorCourses Tests (tested indirectly via Create)

        [TestMethod]
        public void Create_Post_NullSelectedCourses_DoesNotAddCourseAssignments()
        {
            SeedData();
            var instructor = new Instructor
            {
                LastName = "Solo",
                FirstMidName = "Han",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, null);

            var saved = _context.Instructors.Where(i => i.LastName == "Solo").First();
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.AreEqual(0, assignments.Count);
        }

        [TestMethod]
        public void Create_Post_EmptySelectedCourses_DoesNotAddCourseAssignments()
        {
            SeedData();
            var instructor = new Instructor
            {
                LastName = "Empty",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, new string[] { });

            var saved = _context.Instructors.Where(i => i.LastName == "Empty").First();
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.AreEqual(0, assignments.Count);
        }

        #endregion

        #region Delete Tests

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = result as StatusCodeResult;
            Assert.IsNotNull(statusResult);
            Assert.AreEqual(400, statusResult.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsInstructor()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Delete(instructorId) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Kim", model.LastName);
        }

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructor()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.DeleteConfirmed(instructorId);

            Assert.IsInstanceOfType(result, typeof(RedirectToActionResult));
            Assert.AreEqual(0, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.DeleteConfirmed(instructorId) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            SeedData();
            var instructorId = _context.Instructors.First().ID;

            // Set instructor as department administrator
            var dept = _context.Departments.First();
            dept.InstructorID = instructorId;
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructorId);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.IsNull(updatedDept.InstructorID);
        }

        #endregion
    }
}

