using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _context = SchoolContextHelper.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _service = new NotificationService();
            // Drain the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            // Drain the queue after tests
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
            _controller.Dispose();
            _context.Dispose();
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            var value = result.Value;
            Assert.IsNotNull(value);

            // Verify success and count using dynamic
            var json = System.Text.Json.JsonSerializer.Serialize(value);
            Assert.IsTrue(json.Contains("\"success\":true"));
            Assert.IsTrue(json.Contains("\"count\":0"));
