+using ContosoUniversity.Controllers;
+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using ContosoUniversity.Tests.TestHelpers;
+using Microsoft.AspNetCore.Mvc;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+
+namespace ContosoUniversity.Tests.Controllers
+{
+    // Concrete subclass to test BaseController's protected methods
+    public class TestableController : BaseController
+    {
+        public TestableController(SchoolContext context) : base(context)
+        {
+        }
+
+        public void CallSendEntityNotification(string entityType, string entityId, EntityOperation operation)
+        {
+            SendEntityNotification(entityType, entityId, operation);
+        }
+
+        public void CallSendEntityNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
+        {
+            SendEntityNotification(entityType, entityId, entityDisplayName, operation);
+        }
+
+        public void CallDispose()
+        {
+            Dispose(true);
+        }
+
+        public NotificationService GetNotificationService() => notificationService;
+    }
+
+    [TestClass]
+    public class BaseControllerTests
+    {
+        private SchoolContext _context;
+        private TestableController _controller;
+        private NotificationService _drainService;
+
+        [TestInitialize]
+        public void Setup()
+        {
+            _context = SchoolContextHelper.CreateInMemoryContext();
+            _controller = new TestableController(_context);
+            _drainService = new NotificationService();
+            // Drain the static queue
+            while (_drainService.ReceiveNotification() != null) { }
+        }
+
+        [TestCleanup]
+        public void Cleanup()
+        {
+            while (_drainService.ReceiveNotification() != null) { }
+            _drainService.Dispose();
+            _controller.Dispose();
+            _context.Dispose();
+        }
+
+        [TestMethod]
+        public void SendEntityNotification_WithDisplayName_EnqueuesNotification()
+        {
+            _controller.CallSendEntityNotification("Student", "1", "John Doe", EntityOperation.CREATE);
+
+            var notification = _drainService.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Student", notification.EntityType);
+            Assert.AreEqual("1", notification.EntityId);
+            Assert.AreEqual("CREATE", notification.Operation);
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        public void SendEntityNotification_WithoutDisplayName_EnqueuesNotification()
+        {
+            _controller.CallSendEntityNotification("Course", "101", EntityOperation.UPDATE);
+
+            var notification = _drainService.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("Course", notification.EntityType);
+            Assert.AreEqual("101", notification.EntityId);
+            Assert.AreEqual("UPDATE", notification.Operation);
+        }
+
+        [TestMethod]
+        public void SendEntityNotification_UsesSystemAsDefaultUser()
+        {
+            _controller.CallSendEntityNotification("Test", "1", EntityOperation.CREATE);
+
+            var notification = _drainService.ReceiveNotification();
+            Assert.IsNotNull(notification);
+            Assert.AreEqual("System", notification.CreatedBy);
+        }
+
+        [TestMethod]
+        public void Dispose_DoesNotThrow()
+        {
+            var context = SchoolContextHelper.CreateInMemoryContext();
+            var controller = new TestableController(context);
+
+            controller.CallDispose();
+            // Should not throw
+        }
+
+        [TestMethod]
+        public void Dispose_DisposesNotificationService()
+        {
+            var context = SchoolContextHelper.CreateInMemoryContext();
+            var controller = new TestableController(context);
+
+            controller.CallDispose();
+            // Verify notification service was disposed by checking it doesn't throw
+            // (NotificationService.Dispose is no-op, but verify the flow works)
+        }
+
+        [TestMethod]
+        public void Constructor_SetsDbContext()
+        {
+            var context = SchoolContextHelper.CreateInMemoryContext();
+            var controller = new TestableController(context);
+
+            // Verify the controller can access db
+            Assert.IsNotNull(controller.GetNotificationService());
+            controller.Dispose();
+            context.Dispose();
+        }
+    }
+}
